mapper.select:
SELECT 
FROM domain_package
WHERE stable_key = #{stableKey}

    AND workspace_id = #{workspaceId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}


    AND layer = 'PLATFORM_STANDARD'

SELECT 
FROM domain_package
WHERE parent_package_id = #{parentPackageId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}

    AND id > #{lastId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}

ORDER BY id ASC
LIMIT #{size}

SELECT 
FROM domain_package


        AND workspace_id = #{filter.workspaceId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}


        AND layer = #{filter.layer}


        AND status = #{filter.status}


        AND parent_package_id = #{filter.parentPackageId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}


        AND stable_key LIKE CONCAT('%', #{filter.stableKeyLike}, '%')


        AND name LIKE CONCAT('%', #{filter.nameLike}, '%')


        AND id > #{lastId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}


ORDER BY id ASC
LIMIT #{size}

mapper.update:
UPDATE domain_package
SET status = #{newStatus, typeHandler=com.pdp.persistence.typehandler.StringEnumTypeHandler},
    updated_at = #{now, typeHandler=com.pdp.persistence.typehandler.InstantTypeHandler},
    revision = revision + 1
WHERE id = #{id, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}
  AND revision = #{expectedRevision}

UPDATE domain_package
SET current_published_version_id = #{currentPublishedVersionId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler},
    updated_at = #{now, typeHandler=com.pdp.persistence.typehandler.InstantTypeHandler},
    revision = revision + 1
WHERE id = #{id, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}
  AND revision = #{expectedRevision}
